<div class="en">
<svg viewBox="0 0 700 420" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="30" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Liquidity That Never Came Back, a Month Later</text>
  <text x="20" y="50" fill="#a1a1aa" font-size="13" font-family="sans-serif">Order-book depth within 1% of mid-price (before Oct 10 crash vs. early Nov)</text>
  <rect x="470" y="18" width="12" height="12" fill="#71717a"/><text x="486" y="28" fill="#d4d4d8" font-size="13" font-family="sans-serif">Before crash (10/9)</text>
  <rect x="470" y="38" width="12" height="12" fill="#f87171"/><text x="486" y="48" fill="#d4d4d8" font-size="13" font-family="sans-serif">A month later (early Nov)</text>
  <line x1="60" y1="360" x2="660" y2="360" stroke="rgba(255,255,255,.15)"/>
